 73	function basePromptIdForRole(role: PromptAssemblyInput["role"]): BasePromptId {
 74	  switch (role) {
 75	    case "story_implementor":
 76	      return "story-implementor";
 77	    case "story_verifier":
 78	      return "story-verifier";
 79	    case "quick_fixer":
 80	      return "quick-fixer";
 81	    case "epic_verifier":
 82	      return "epic-verifier";
 83	    case "epic_synthesizer":
 84	      return "epic-synthesizer";
 85	  }
 86	}
 87	
 88	function snippetIdsForInput(input: PromptAssemblyInput): SnippetId[] {
 89	  switch (input.role) {
 90	    case "story_implementor": {
 91	      const snippetIds: SnippetId[] = [
 92	        "reading-journey",
 93	        "gate-instructions",
 94	        "report-contract",
 95	      ];
 96	      if (typeof input.selfReviewPass === "number" && input.selfReviewPass >= 1) {
 97	        snippetIds.push(selfReviewSnippetId(input.selfReviewPass));
 98	      }
 99	      return snippetIds;
100	    }
101	    case "story_verifier":
102	      return [
103	        "reading-journey",
104	        "gate-instructions",
105	        "report-contract",
106	        "mock-audit",
107	      ];
108	    case "quick_fixer":
109	      return ["gate-instructions", "report-contract"];
110	    case "epic_verifier":
111	      return ["gate-instructions", "report-contract", "mock-audit"];
112	    case "epic_synthesizer":
113	      return ["gate-instructions", "report-contract"];
114	  }
115	}
116	
117	function selfReviewSnippetId(pass: number): SnippetId {
118	  if (pass <= 1) {
119	    return "self-review-pass-1";
120	  }
121	  if (pass === 2) {
122	    return "self-review-pass-2";
123	  }
124	  return "self-review-pass-3";
125	}
