127	function buildReadingJourney(input: PromptAssemblyInput): string {
128	  if (input.role === "quick_fixer") {
129	    return "";
130	  }
131	
132	  const companionLines = (input.techDesignCompanionPaths ?? [])
133	    .map((path) => `- ${path}`)
134	    .join("\n");
135	  const common = [
136	    `- Story: ${input.storyPath ?? "n/a"}`,
137	    `- Epic: ${input.epicPath ?? "n/a"}`,
138	    `- Tech Design Index: ${input.techDesignPath ?? "n/a"}`,
139	    companionLines ? `- Tech Design Companions:\n${companionLines}` : "",
140	    `- Test Plan: ${input.testPlanPath ?? "n/a"}`,
141	  ]
142	    .filter(Boolean)
143	    .join("\n");
144	
145	  if (input.role === "story_implementor") {
146	    return [
147	      "Read the current story first.",
148	      common,
149	      "Then read the full tech-design set before implementation starts.",
150	      "Read each file in 500-line chunks if large.",
151	      "Reflect after each chunk before you move on.",
152	    ].join("\n");
153	  }
154	
155	  if (input.role === "story_verifier") {
156	    return [
157	      "Read the current story and the full tech-design set before you judge the implementation.",
158	      common,
159	      "As you read, extract AC and TC evidence.",
160	      "Then verify against code, tests, and artifacts before filing findings.",
161	      "Read each file in 500-line chunks if large.",
162	      "Reflect after each chunk before you move on.",
163	    ].join("\n");
164	  }
165	
166	  return [
167	    "Read the epic-level artifacts before you judge the whole implementation set.",
168	    common,
169	  ].join("\n");
170	}
