229	function interpolateTemplate(
230	  template: string,
231	  values: Record<string, string>
232	): string {
233	  return template.replaceAll(/{{([A-Z_]+)}}/g, (_, key: string) => {
234	    return values[key] ?? "";
235	  });
236	}
