113	async function prepareStoryContext(input: {
114	  specPackRoot: string;
115	  storyId: string;
116	  configPath?: string;
117	  providerOverride?: ProviderName;
118	}): Promise<PreparedStoryContext | WorkflowFailure> {
119	  const inspection = await inspectSpecPack(input.specPackRoot);
120	  if (inspection.status !== "ready") {
121	    return {
122	      outcome: "blocked",
123	      errors: [
124	        blockedError(
125	          "INVALID_SPEC_PACK",
126	          "Spec-pack inspection must be ready before story implementation can start.",
127	          inspection.blockers.join("; ") || inspection.notes.join("; ")
128	        ),
129	      ],
130	    };
131	  }
132	
133	  const story = inspection.stories.find((candidate) => candidate.id === input.storyId);
134	  if (!story) {
135	    return {
136	      outcome: "blocked",
137	      errors: [
138	        blockedError(
139	          "INVALID_SPEC_PACK",
140	          `Story '${input.storyId}' was not found in the resolved story inventory.`
141	        ),
142	      ],
143	    };
144	  }
145	
146	  const config = await loadRunConfig({
147	    specPackRoot: inspection.specPackRoot,
148	    configPath: input.configPath,
149	  });
150	  const gateResolution = await resolveVerificationGates({
151	    specPackRoot: inspection.specPackRoot,
152	  });
153	  if (gateResolution.status !== "ready" || !gateResolution.verificationGates) {
154	    return {
155	      outcome: "blocked",
156	      errors: gateResolution.errors.length
157	        ? gateResolution.errors
158	        : [
159	            blockedError(
160	              "VERIFICATION_GATE_UNRESOLVED",
161	              "Verification gates must be resolved before story implementation can start."
162	            ),
163	          ],
164	    };
165	  }
166	
167	  const provider =
168	    input.providerOverride ??
169	    (config.story_implementor.secondary_harness === "none"
170	      ? "claude-code"
171	      : config.story_implementor.secondary_harness);
172	
173	  return {
174	    specPackRoot: inspection.specPackRoot,
175	    story: {
176	      id: story.id,
177	      title: story.title,
178	      path: story.path,
179	    },
180	    provider,
181	    model: config.story_implementor.model,
182	    reasoningEffort: config.story_implementor.reasoning_effort,
183	    implementationPromptInsertPath:
184	      inspection.inserts.customStoryImplPromptInsert === "present"
185	        ? join(inspection.specPackRoot, "custom-story-impl-prompt-insert.md")
186	        : undefined,
187	    gateCommands: {
188	      story: gateResolution.verificationGates.storyGate,
189	      epic: gateResolution.verificationGates.epicGate,
190	    },
191	    paths: {
192	      epicPath: inspection.artifacts.epicPath,
193	      techDesignPath: inspection.artifacts.techDesignPath,
194	      techDesignCompanionPaths: inspection.artifacts.techDesignCompanionPaths,
195	      testPlanPath: inspection.artifacts.testPlanPath,
196	    },
197	    selfReviewPasses: config.self_review.passes,
198	  };
199	}
