201	function executionFailureError(input: {
202	  provider: ProviderName;
203	  stderr: string;
204	  errorCode?: string;
205	}): CliError {
206	  if (input.errorCode === "ENOENT") {
207	    return blockedError(
208	      "PROVIDER_UNAVAILABLE",
209	      `Provider executable is unavailable for ${input.provider}.`,
210	      input.stderr
211	    );
212	  }
213	
214	  return blockedError(
215	    "PROVIDER_UNAVAILABLE",
216	    `Provider execution failed for ${input.provider}.`,
217	    input.stderr
218	  );
219	}
